class Solution {
    public List<Integer> findAllPeople(int n, int[][] meetings, int firstPerson) {
        List<Integer> secretSharers = new ArrayList<>();
        for (int[] meeting : meetings) {
            int x = meeting[0];
            int y = meeting[1];
            int time = meeting[2];
            if (secretSharers.contains(x) && secretSharers.contains(y)) {
                secretSharers.add(x);
